import{_ as o,o as a,c as n,ac as t}from"./chunks/framework.DnBnwVZk.js";const g=JSON.parse('{"title":"SpringBoot源码-@Configuration配置处理","description":"","frontmatter":{"date":"2021-04-24T12:10:29.000Z","categories":["Spring"],"tags":[null],"publish":false},"headers":[],"relativePath":"views/spring/2020/SpringConfigurationClass.md","filePath":"views/spring/2020/SpringConfigurationClass.md","lastUpdated":1775803235000}'),e={name:"views/spring/2020/SpringConfigurationClass.md"};function r(l,i,s,u,c,p){return a(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1619266229000"},[...i[0]||(i[0]=[t('<h1 id="springboot源码-configuration配置处理" tabindex="-1">SpringBoot源码-@Configuration配置处理 <a class="header-anchor" href="#springboot源码-configuration配置处理" aria-label="Permalink to &quot;SpringBoot源码-@Configuration配置处理&quot;">​</a></h1><h2 id="_1-解析class-读取beandefinition" tabindex="-1">1. 解析Class，读取BeanDefinition <a class="header-anchor" href="#_1-解析class-读取beandefinition" aria-label="Permalink to &quot;1. 解析Class，读取BeanDefinition&quot;">​</a></h2><p>时机：refresh context，调用所有的BeanFactoryPostProcessor，其中SharedMetadataReaderFactoryContextInitializer会添加一个BeanPostProcessor:internalConfigurationAnnotationProcessor,这个会在接下来被调用 对象：FullConfiguration：@Configuration注解的类；LiteConfiguration:@Import注解的类 顺寻：根据Class的@Order进行排序 parse: 调用ConfigurationClassParser对象的parse方法来进行解析：</p><ol><li>根据@Conditional判断是否需要跳过</li><li>处理@PropertySource</li><li>处理@ComponentScan：读取指定的包下的所有子类，挑选@Component注解的类，读取信息成为BeanDefinitionHolder，底层调用ComponentScanAnnotationParser类的parse方法： <ol><li>ClassPathBeanDefinitionScanner：扫描<code>classpath*:com/package/name/**/*.class</code>，**注意，如果basePackage没有配置，则默认取@Configuration对应的类的包名</li><li>判断依据：MBean和@Component注解，包括其子注解</li><li>处理的注解： <ul><li>@Lazy</li><li>@Primary</li><li>@Role</li><li>@Description</li><li>@DependsOn</li></ul></li></ol></li><li>处理@Import： <ul><li>@SpringBootApplication <ul><li>@EnableAutoConfiguration <ul><li>@Import(AutoConfigurationImportSelector.class)</li><li>@AutoConfigurationPackage <ul><li>@Import(AutoConfigurationPackages.Registrar.class)</li></ul></li></ul></li></ul></li><li>上面@Import进来的class分为两种： <ul><li>ImportSelector：决定哪些Configuration类可以被选中，其子类DeferredImportSelector提供了分组的形式来细化管理Import <ul><li>AutoConfigurationImportSelector:处理SpringAutoConfiguration包下面定义的各种Bean等</li></ul></li><li>ImportBeanDefinitionRegistrar：注册BeanDefinition</li></ul></li></ul></li><li>处理@ImportResource</li><li>处理@Bean</li><li>处理接口里的default方法</li><li>处理父类</li><li>递归处理过程中导入的ImportSelector，导入其定义的Configuration类，缓存</li></ol><h2 id="_2-校验configuration" tabindex="-1">2. 校验Configuration <a class="header-anchor" href="#_2-校验configuration" aria-label="Permalink to &quot;2. 校验Configuration&quot;">​</a></h2><h2 id="_3-处理importselector导入的配置类" tabindex="-1">3. 处理ImportSelector导入的配置类 <a class="header-anchor" href="#_3-处理importselector导入的配置类" aria-label="Permalink to &quot;3. 处理ImportSelector导入的配置类&quot;">​</a></h2><h2 id="_4-清理工作" tabindex="-1">4. 清理工作 <a class="header-anchor" href="#_4-清理工作" aria-label="Permalink to &quot;4. 清理工作&quot;">​</a></h2>',7)])])}const d=o(e,[["render",r]]);export{g as __pageData,d as default};
